**Streak Card Specifics:**
```javascript
async function drawStreakCard(ctx, data, canvas) {
  const { currentStreak, calendarData, totalLevels, totalXP } = data;

  // Title
  ctx.font = 'bold 72px system-ui';
  ctx.fillStyle = '#FFD700';
  ctx.textAlign = 'center';
  ctx.fillText(`🔥 ${currentStreak} DAY STREAK 🔥`, canvas.width/2, 200);

  // Calendar grid (last 30 days)
  drawCalendarGrid(ctx, calendarData, canvas.width/2 - 200, 280, 400, 200);

  // Stats
  ctx.font = '32px system-ui';
  ctx.fillStyle = '#ffffff';
  ctx.fillText(`${totalLevels} levels completed`, canvas.width/2, 550);
  ctx.fillText(`${totalXP.toLocaleString()} XP earned`, canvas.width/2, 600);
}

function drawCalendarGrid(ctx, days, x, y, width, height) {
  const cellSize = width / 7;
  const rows = Math.ceil(days.length / 7);

  days.forEach((day, i) => {
    const col = i % 7;
    const row = Math.floor(i / 7);
    const cx = x + col * cellSize + cellSize/2;
    const cy = y + row * (height/rows) + (height/rows)/2;

    // Circle: green if played, gray if not
    ctx.beginPath();
    ctx.arc(cx, cy, cellSize * 0.35, 0, Math.PI * 2);
    ctx.fillStyle = day.played ? '#00C853' : '#333333';
    ctx.fill();

    if (day.isToday) {
      ctx.strokeStyle = '#FFD700';
      ctx.lineWidth = 3;
      ctx.stroke();
    }
  });
}
```

