class GameHistory {
  constructor() {
    this.states = [];
    this.currentIndex = -1;
    this.thumbnails = [];  // Cached mini-renders
  }

  push(state) {
    // Truncate future if not at end
    this.states = this.states.slice(0, this.currentIndex + 1);
    this.thumbnails = this.thumbnails.slice(0, this.currentIndex + 1);

    this.states.push(structuredClone(state));
    this.thumbnails.push(null);  // Generate lazily
    this.currentIndex++;
  }

  undo() {
    if (this.currentIndex > 0) {
      this.currentIndex--;
      return this.states[this.currentIndex];
    }
    return null;
  }

  redo() {
    if (this.currentIndex < this.states.length - 1) {
      this.currentIndex++;
      return this.states[this.currentIndex];
    }
    return null;
  }

  jumpTo(index) {
    if (index >= 0 && index < this.states.length) {
      this.currentIndex = index;
      return this.states[index];
    }
    return null;
  }

  getThumbnail(index) {
    if (!this.thumbnails[index]) {
      this.thumbnails[index] = this.generateThumbnail(this.states[index]);
    }
    return this.thumbnails[index];
  }

  generateThumbnail(state) {
    // Render state to small canvas (40x60px)
    const canvas = document.createElement('canvas');
    canvas.width = 40;
    canvas.height = 60;
    // ... mini render logic
    return canvas.toDataURL();
  }
}
