```javascript
class SolutionRecorder {
  constructor(canvas, renderer) {
    this.canvas = canvas;
    this.renderer = renderer;
    this.frames = [];
  }

  captureFrame(state) {
    // Clone canvas at current state
    const frame = document.createElement('canvas');
    frame.width = 400;
    frame.height = 600;
    const ctx = frame.getContext('2d');

    // Render state to frame
    this.renderer.renderToContext(ctx, state);

    this.frames.push(frame);
  }

  async generateGIF(options = {}) {
    const {
      width = 400,
      height = 600,
      delay = 500,  // ms between frames
      quality = 10
    } = options;

    const gif = new GIF({
      workers: 2,
      quality,
      width,
      height,
      workerScript: '/shared/gif.worker.js'
    });

    for (const frame of this.frames) {
      gif.addFrame(frame, { delay, copy: true });
    }

    return new Promise((resolve, reject) => {
      gif.on('finished', blob => resolve(blob));
      gif.on('error', reject);
      gif.render();
    });
  }
}
