**Skill Score Calculation:**
```javascript
function calculateSkillScore(metrics) {
  const w = { efficiency: 0.4, speed: 0.2, consistency: 0.2, persistence: 0.2 };

  const efficiency = Math.min(1, 1 / metrics.averageEfficiency);  // Closer to optimal = higher
  const speed = Math.min(1, metrics.expectedTime / metrics.averageTime);
  const consistency = 1 - Math.min(1, metrics.variance / 10);
  const persistence = 1 - metrics.abandonRate;

  return Math.round(
    (efficiency * w.efficiency +
     speed * w.speed +
     consistency * w.consistency +
     persistence * w.persistence) * 100
  );
}
```

**Level Selection:**
```javascript
function selectNextLevel(skillScore, availableLevels) {
  const targetDifficulty = skillScore / 100;
  const bandwidth = 0.15;  // ±15%

  // Find levels in target range
  const suitable = availableLevels.filter(level => 
    level.difficulty >= targetDifficulty - bandwidth &&
    level.difficulty <= targetDifficulty + bandwidth &&
    !level.completed
  );

  // Prefer unplayed, then least-played
  suitable.sort((a, b) => a.playCount - b.playCount);

  return suitable[0] || randomChoice(availableLevels);
}
