## API Design

### shared/storage.js
```javascript
const STORAGE_PREFIX = 'mobileGaming_';
const SCHEMA_VERSION = 1;

export function save(key, data) {
  try {
    const payload = JSON.stringify({
      v: SCHEMA_VERSION,
      data,
      updatedAt: Date.now()
    });
    localStorage.setItem(STORAGE_PREFIX + key, payload);
    return true;
  } catch (e) {
    console.warn('Storage save failed:', e);
    return false;
  }
}

export function load(key, defaultValue = null) {
  try {
    const raw = localStorage.getItem(STORAGE_PREFIX + key);
    if (!raw) return defaultValue;

    const { v, data } = JSON.parse(raw);

    // Handle migrations
    if (v < SCHEMA_VERSION) {
      return migrate(data, v, SCHEMA_VERSION);
    }

    return data;
  } catch (e) {
    console.warn('Storage load failed:', e);
    return defaultValue;
  }
}

export function remove(key) {
  localStorage.removeItem(STORAGE_PREFIX + key);
}

export function clear() {
  // Only clear our keys, not all localStorage
  Object.keys(localStorage)
    .filter(k => k.startsWith(STORAGE_PREFIX))
    .forEach(k => localStorage.removeItem(k));
}

export function exportData() {
  const data = {};
  Object.keys(localStorage)
    .filter(k => k.startsWith(STORAGE_PREFIX))
    .forEach(k => {
      data[k.replace(STORAGE_PREFIX, '')] = load(k.replace(STORAGE_PREFIX, ''));
    });
  return JSON.stringify(data, null, 2);
}

export function importData(jsonString) {
  const data = JSON.parse(jsonString);
  Object.entries(data).forEach(([key, value]) => {
    save(key, value);
  });
}
```

