export function addXP(amount, source = 'unknown') {
  const profile = getProfile();
  const oldLevel = profile.level;

  profile.xp += amount;
  profile.level = calculateLevel(profile.xp);

  // Track XP source for analytics
  profile.xpHistory = profile.xpHistory || [];
  profile.xpHistory.push({ amount, source, timestamp: Date.now() });

  saveProfile(profile);

  // Check for level up
  if (profile.level > oldLevel) {
    const unlock = UNLOCKS[profile.level];
    if (unlock) {
      unlockCosmetic(unlock.id);
    }
    return { leveledUp: true, newLevel: profile.level, unlock };
  }

  return { leveledUp: false };
}

export function calculateLevel(xp) {
  for (let i = LEVEL_THRESHOLDS.length - 1; i >= 0; i--) {
    if (xp >= LEVEL_THRESHOLDS[i]) return i + 1;
  }
  return 1;
}

export function getXPForNextLevel(currentXP) {
  const level = calculateLevel(currentXP);
  if (level >= LEVEL_THRESHOLDS.length) return null;
  return LEVEL_THRESHOLDS[level];
}

export function unlockCosmetic(id) {
  const profile = getProfile();
  if (!profile.unlockedCosmetics.includes(id)) {
    profile.unlockedCosmetics.push(id);
    saveProfile(profile);
  }
}

export function isUnlocked(id) {
  const profile = getProfile();
  return profile.unlockedCosmetics.includes(id);
}

export function recordGamePlayed(gameSlug, result) {
  const profile = getProfile();

  if (!profile.gamesPlayed[gameSlug]) {
    profile.gamesPlayed[gameSlug] = {
      played: 0,
      completed: 0,
      stars: 0,
      bestStreak: 0,
      currentStreak: 0
    };
  }

  const game = profile.gamesPlayed[gameSlug];
  game.played++;

  if (result.completed) {
    game.completed++;
    game.stars += result.stars || 0;
    game.currentStreak++;
    game.bestStreak = Math.max(game.bestStreak, game.currentStreak);
  } else {
    game.currentStreak = 0;
  }

  saveProfile(profile);
}
