- [ ] Redo returns next state
- [ ] Branching truncates future
- [ ] Max size enforced
- [ ] States are deep cloned
- [ ] canUndo/canRedo accurate

# Implement Daily Challenge Seeding

## Context
Daily challenges create:
- Reason to return each day
- Shared experience worldwide
- Competition without backend
- Streak motivation

## Key Requirement
Same date + same game = same puzzle for all users globally

## Implementation (shared/daily.js)
```javascript
import { createRNG } from './rng.js';
import { load, save } from './storage.js';

const SALT = 'mobile-gaming-daily-v1';

/**
 * Hash a string to a number
 */
function hashString(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash |= 0; // Convert to 32-bit integer
  }
  return Math.abs(hash);
}

/**
 * Get today's date string (UTC to ensure global consistency)
 */
export function getTodayString() {
  return new Date().toISOString().slice(0, 10); // "2026-03-05"
}

/**
 * Get seed for today's challenge
 */
export function getDailySeed() {
  return hashString(getTodayString() + SALT);
}

/**
 * Get seed for a specific game's daily challenge
 */
export function getGameDailySeed(gameSlug) {
  return hashString(getDailySeed() + gameSlug);
}

/**
 * Check if daily challenge completed for a game
 */
export function isDailyCompleted(gameSlug) {
  const key = `daily_${getTodayString()}_${gameSlug}`;
  const result = load(key);
  return result?.completed === true;
}

/**
 * Record daily challenge completion
 */
export function recordDailyCompletion(gameSlug, result) {
  const key = `daily_${getTodayString()}_${gameSlug}`;
  save(key, {
    completed: true,
    moves: result.moves,
    time: result.time,
    stars: result.stars,
    completedAt: Date.now()
  });

  updateDailyStreak();
}

/**
 * Update daily streak tracking
 */
export function updateDailyStreak() {
  const profile = load('profile', { dailyStreak: 0, lastDailyDate: null });
  const today = getTodayString();

  if (profile.lastDailyDate === today) {
    return; // Already counted today
  }

  const yesterday = new Date(Date.now() - 86400000).toISOString().slice(0, 10);

  if (profile.lastDailyDate === yesterday) {
    profile.dailyStreak++;
  } else {
    profile.dailyStreak = 1; // Streak broken, restart
  }

  profile.longestStreak = Math.max(
    profile.longestStreak || 0, 
    profile.dailyStreak
  );
  profile.lastDailyDate = today;

  save('profile', profile);
}

/**
 * Get current streak info
 */
export function getStreakInfo() {
  const profile = load('profile', {});
  const today = getTodayString();
  const yesterday = new Date(Date.now() - 86400000).toISOString().slice(0, 10);

  // Check if streak is still active
  const isActive = profile.lastDailyDate === today || 
                   profile.lastDailyDate === yesterday;

  return {
    current: isActive ? (profile.dailyStreak || 0) : 0,
    longest: profile.longestStreak || 0,
    completedToday: profile.lastDailyDate === today
  };
}
```

