**Audio Manager:**
```javascript
class AmbientAudio {
  constructor() {
    this.tracks = {
      rain: '/audio/ambient/rain-loop.mp3',
      piano: '/audio/ambient/soft-piano.mp3',
      nature: '/audio/ambient/forest.mp3',
      lofi: '/audio/ambient/lofi-beats.mp3',
      ocean: '/audio/ambient/ocean-waves.mp3'
    };
    this.audio = new Audio();
    this.audio.loop = true;
    this.volume = 0.3;
  }

  async play(track) {
    if (!this.tracks[track]) return;

    // Crossfade if already playing
    if (!this.audio.paused) {
      await this.fadeOut(500);
    }

    this.audio.src = this.tracks[track];
    this.audio.volume = 0;
    await this.audio.play();
    await this.fadeIn(1000);
  }

  async fadeIn(duration) {
    const steps = 20;
    const stepTime = duration / steps;
    const stepVolume = this.volume / steps;

    for (let i = 0; i < steps; i++) {
      await new Promise(r => setTimeout(r, stepTime));
      this.audio.volume = Math.min(this.volume, this.audio.volume + stepVolume);
    }
  }

  async fadeOut(duration) {
    const steps = 20;
    const stepTime = duration / steps;
    const stepVolume = this.audio.volume / steps;

    for (let i = 0; i < steps; i++) {
      await new Promise(r => setTimeout(r, stepTime));
      this.audio.volume = Math.max(0, this.audio.volume - stepVolume);
    }
    this.audio.pause();
  }

  stop() {
    this.fadeOut(500);
  }
}
```

